svg.script:
(() => {
  const svg = document.documentElement;
  const movingGroups = [document.getElementById("district-base"), document.getElementById("enterprise-bubbles")];
  const bounds = { x: 72, y: 38 };
  let offsetX = 0;
  let offsetY = 0;
  let startX = 0;
  let startY = 0;
  let startOffsetX = 0;
  let startOffsetY = 0;
  let pointerId = null;
  let dragging = false;
  let moved = false;
  let longPressTimer = null;

  const clamp = (value, limit) => Math.max(-limit, Math.min(limit, value));
  const applyOffset = () => {
    const transform = `translate(${offsetX.toFixed(2)} ${offsetY.toFixed(2)})`;
    movingGroups.forEach((group) => group?.setAttribute("transform", transform));
  };
  const activateDrag = () => {
    if (pointerId === null) return;
    dragging = true;
    svg.classList.add("is-dragging");
    try { svg.setPointerCapture(pointerId); } catch (_) { /* pointer may already be released */ }
  };
  const clearTimer = () => {
    if (longPressTimer !== null) window.clearTimeout(longPressTimer);
    longPressTimer = null;
  };
  const finishDrag = (event) => {
    clearTimer();
    if (pointerId !== null && svg.hasPointerCapture?.(pointerId)) svg.releasePointerCapture(pointerId);
    if (moved) event?.preventDefault?.();
    pointerId = null;
    dragging = false;
    moved = false;
    svg.classList.remove("is-dragging");
  };

  svg.addEventListener("pointerdown", (event) => {
    if (event.pointerType === "mouse" && event.button !== 0) return;
    pointerId = event.pointerId;
    startX = event.clientX;
    startY = event.clientY;
    startOffsetX = offsetX;
    startOffsetY = offsetY;
    moved = false;
    clearTimer();
    if (event.pointerType === "mouse") activateDrag();
    else longPressTimer = window.setTimeout(activateDrag, 360);
  });

  svg.addEventListener("pointermove", (event) => {
    if (event.pointerId !== pointerId) return;
    const deltaX = event.clientX - startX;
    const deltaY = event.clientY - startY;
    if (!dragging) {
      if (Math.hypot(deltaX, deltaY) > 9) finishDrag(event);
      return;
    }
    event.preventDefault();
    moved = moved || Math.hypot(deltaX, deltaY) > 2;
    offsetX = clamp(startOffsetX + deltaX, bounds.x);
    offsetY = clamp(startOffsetY + deltaY, bounds.y);
    applyOffset();
  }, { passive: false });

  svg.addEventListener("pointerup", finishDrag);
  svg.addEventListener("pointercancel", finishDrag);
  svg.addEventListener("dblclick", () => {
    offsetX = 0;
    offsetY = 0;
    applyOffset();
  });
  svg.addEventListener("keydown", (event) => {
    const movement = 12;
    if (event.key === "ArrowLeft") offsetX = clamp(offsetX - movement, bounds.x);
    else if (event.key === "ArrowRight") offsetX = clamp(offsetX + movement, bounds.x);
    else if (event.key === "ArrowUp") offsetY = clamp(offsetY - movement, bounds.y);
    else if (event.key === "ArrowDown") offsetY = clamp(offsetY + movement, bounds.y);
    else if (event.key === "Home") { offsetX = 0; offsetY = 0; }
    else return;
    event.preventDefault();
    applyOffset();
  });
})();
